def detect_cycle_undirected(graph):
    """
    Undirected bir grafikte döngü olup olmadığını tespit eder.

    Args:
        graph: Grafiği temsil eden sözlük. Anahtarlar düğümleri temsil eder
               ve değerler, o düğüme komşu düğümlerin bir listesidir.

    Returns:
        Grafikte bir döngü varsa True, aksi takdirde False.
    """

    def dfs(node, visited, parent):
        visited[node] = True

        for neighbor in graph[node]:
            if not visited[neighbor]:
                if dfs(neighbor, visited, node):
                    return True
            elif neighbor != parent:
                return True
        return False

    num_nodes = len(graph)
    visited = {node: False for node in graph}

    for node in graph:
        if not visited[node]:
            if dfs(node, visited, -1):
                return True
    return False

